package com.user.servlet; import com.DB.DBConnect; import com.DAO.BookDAOImpl; import com.entity.BookDtls; import javax.servlet.annotation.*; import javax.servlet.http.*; import java.io.*; import java.nio.file.*;
@WebServlet("/add_old_book") @MultipartConfig public class AddOldBook extends HttpServlet {protected void doPost(HttpServletRequest r,HttpServletResponse p)throws IOException{HttpSession s=r.getSession();try{Part part=r.getPart("bimg");String fn=Paths.get(part.getSubmittedFileName()).getFileName().toString();BookDtls b=new BookDtls(r.getParameter("bname"),r.getParameter("author"),r.getParameter("price"),"Old","Active",fn,r.getParameter("user"));try(var c=DBConnect.getConn()){if(new BookDAOImpl(c).addBooks(b)){String path=getServletContext().getRealPath("")+File.separator+"book";new File(path).mkdirs();part.write(path+File.separator+fn);s.setAttribute("succMsg","Book listed successfully");}else s.setAttribute("failedMsg","Could not list book");}}catch(Exception e){s.setAttribute("failedMsg",e.getMessage());}p.sendRedirect("sell_book.jsp");}}
